import { useEffect, useState } from "react";
import socket from "../socket";
import { motion } from "framer-motion";

const colors = ["#ff3355", "#3399ff", "#ffcc00", "#33cc66"];

function Player() {
  const [name, setName] = useState("");
  const [joined, setJoined] = useState(false);
  const [question, setQuestion] = useState(null);
  const [score, setScore] = useState(0);
  const [answered, setAnswered] = useState(false);
  const [time, setTime] = useState(0);
  const [countdown, setCountdown] = useState(0);

  // 🔊 sounds
  const clickSound = new Audio("/sounds/click.mp3");
  const correctSound = new Audio("/sounds/correct.mp3");
  const bgMusic = new Audio("/sounds/bg.mp3");

  useEffect(() => {
    // 🎵 background music
    bgMusic.loop = true;
    bgMusic.volume = 0.3;
    bgMusic.play().catch(() => {});

    socket.on("gameStarted", (data) => {
      // 🔥 countdown effect
      let c = 3;
      setCountdown(c);

      const interval = setInterval(() => {
        c--;
        setCountdown(c);

        if (c === 0) {
          clearInterval(interval);
          setQuestion(data.question);
          setTime(data.time);
          setAnswered(false);
        }
      }, 1000);
    });

    socket.on("nextQuestion", (data) => {
      setQuestion(data.question);
      setTime(data.time);
      setAnswered(false);
    });

    socket.on("timer", setTime);

    socket.on("scoreUpdated", (scores) => {
      if (scores[name] !== undefined) {
        setScore(scores[name]);
      }
    });

    socket.on("gameOver", () => {
      setQuestion(null);
      alert("🎉 Game Over!");
    });

    return () => {
      socket.off("gameStarted");
      socket.off("nextQuestion");
      socket.off("timer");
      socket.off("scoreUpdated");
      socket.off("gameOver");
      bgMusic.pause();
    };
  }, [name]);

  // ✅ join game
  const joinGame = () => {
    if (!name) return alert("Enter name");
    socket.emit("joinGame", name);
    setJoined(true);
  };

  // ✅ answer (single click only)
  const sendAnswer = (opt) => {
    if (answered) return;

    clickSound.play();

    const correct = opt === question.answer;

    if (correct) correctSound.play();

    socket.emit("answer", { name, correct });

    setAnswered(true);
  };

  // 🎮 JOIN SCREEN
  if (!joined) {
    return (
      <div style={styles.joinContainer}>
        <motion.div
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
        >
          <h1 style={styles.title}>🎮 Join Game</h1>

          <input
            style={styles.input}
            placeholder="Enter nickname"
            value={name}
            onChange={(e) => setName(e.target.value)}
          />

          <button style={styles.joinBtn} onClick={joinGame}>
            JOIN
          </button>
        </motion.div>
      </div>
    );
  }

  // 🎯 GAME SCREEN
  return (
    <div style={styles.container}>
      {countdown > 0 ? (
        <motion.h1
          initial={{ scale: 0 }}
          animate={{ scale: 1.5 }}
          style={{ fontSize: 80 }}
        >
          {countdown}
        </motion.h1>
      ) : (
        <>
          <h2 style={styles.timer}>⏱️ {time}s</h2>

          {question ? (
            <>
              <motion.h2
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                style={styles.question}
              >
                {question.question}
              </motion.h2>

              <div style={styles.grid}>
                {question.options.map((opt, i) => (
                  <motion.button
                    key={i}
                    onClick={() => sendAnswer(opt)}

                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.95 }}

                    initial={{ opacity: 0, y: 100 }}
                    animate={{ opacity: 1, y: 0 }}

                    transition={{ delay: i * 0.1 }}

                    style={{
                      ...styles.answer,
                      background: colors[i],
                      boxShadow: `0 0 20px ${colors[i]}`,
                    }}
                  >
                    {opt}
                  </motion.button>
                ))}
              </div>
            </>
          ) : (
            <h2>Waiting for host...</h2>
          )}

          <h3 style={styles.score}>Score: {score}</h3>
        </>
      )}
    </div>
  );
}

export default Player;

// 🎨 STYLES
const styles = {
  container: {
    minHeight: "100vh",
    background: "linear-gradient(135deg, #0f0f0f, #1a1a1a)",
    color: "white",
    textAlign: "center",
    padding: 20,
  },

  joinContainer: {
    height: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    background: "linear-gradient(135deg, #111, #222)",
    color: "white",
  },

  title: {
    fontSize: 40,
    marginBottom: 20,
  },

  input: {
    padding: 12,
    fontSize: 18,
    borderRadius: 10,
    border: "none",
    marginBottom: 20,
  },

  joinBtn: {
    padding: 12,
    fontSize: 18,
    borderRadius: 10,
    background: "#00e676",
    border: "none",
    color: "black",
    cursor: "pointer",
  },

  timer: {
    fontSize: 24,
    marginBottom: 10,
  },

  question: {
    fontSize: 26,
    marginBottom: 20,
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: 15,
  },

  answer: {
    padding: 30,
    fontSize: 18,
    borderRadius: 15,
    border: "none",
    color: "white",
    cursor: "pointer",
    fontWeight: "bold",
  },

  score: {
    marginTop: 20,
    fontSize: 22,
  },
};
